    --color-kumo-brand: oklch(57.72% .2324 260);
    --color-kumo-brand-hover: var(--color-blue-700,oklch(48.8% .243 264.376));
    --color-kumo-line: var(--color-kumo-neutral-750,oklch(32% 0 0));
